import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React from 'react';
import { HashRouter as Router, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import Footer from './components/Footer';
import Home from './pages/Home';
import Guide from './pages/Guide';
import Booking from './pages/Booking';

const App: React.FC = () => {
  return (
    <Router>
      <div className="flex flex-col min-h-screen">
        <Navbar />
        <main className="flex-grow">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/guia-insider" element={<Guide />} />
            <Route path="/reservar" element={<Booking />} />
          </Routes>
        </main>
        <Footer />
      </div>
    </Router>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Menu, X, ChevronRight } from 'lucide-react';

const Navbar: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { name: 'Inicio', path: '/' },
    { name: 'Guía Insider', path: '/guia-insider' },
  ];

  const isActive = (path: string) => location.pathname === path;

  return (
    <nav className={`fixed w-full z-50 transition-all duration-300 ${isScrolled ? 'bg-white/95 backdrop-blur-md shadow-sm py-3' : 'bg-transparent py-6'}`}>
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center">
          <Link to="/" className="flex flex-col items-center">
            <span className={`text-2xl font-bold tracking-tighter serif ${isScrolled ? 'text-[#4A5D4E]' : 'text-white'}`}>
              Furones
            </span>
            <span className={`text-[10px] uppercase tracking-widest ${isScrolled ? 'text-[#8C7B65]' : 'text-white/80'}`}>
              Casa Rural · Antequera
            </span>
          </Link>

          {/* Desktop Nav */}
          <div className="hidden md:flex items-center space-x-8">
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                className={`text-sm font-medium transition-colors hover:text-[#8C7B65] ${
                  isActive(link.path) 
                    ? (isScrolled ? 'text-[#8C7B65]' : 'text-white border-b border-white/30') 
                    : (isScrolled ? 'text-[#4A5D4E]' : 'text-white/90')
                }`}
              >
                {link.name}
              </Link>
            ))}
            <Link
              to="/reservar"
              className={`px-6 py-2 rounded-full text-sm font-semibold transition-all flex items-center gap-2 ${
                isScrolled 
                  ? 'bg-[#4A5D4E] text-white hover:bg-[#3D4D40]' 
                  : 'bg-white text-[#4A5D4E] hover:bg-white/90 shadow-xl'
              }`}
            >
              Reservar <ChevronRight size={16} />
            </Link>
          </div>

          {/* Mobile Menu Button */}
          <div className="md:hidden">
            <button
              onClick={() => setIsOpen(!isOpen)}
              className={`${isScrolled ? 'text-[#4A5D4E]' : 'text-white'}`}
            >
              {isOpen ? <X size={28} /> : <Menu size={28} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Nav */}
      {isOpen && (
        <div className="md:hidden absolute top-full left-0 w-full bg-white shadow-2xl animate-in slide-in-from-top duration-300">
          <div className="px-4 pt-2 pb-6 space-y-1">
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                onClick={() => setIsOpen(false)}
                className="block px-3 py-4 text-lg font-medium text-[#4A5D4E] border-b border-gray-100"
              >
                {link.name}
              </Link>
            ))}
            <Link
              to="/reservar"
              onClick={() => setIsOpen(false)}
              className="block w-full text-center mt-4 px-3 py-4 bg-[#4A5D4E] text-white rounded-lg font-bold"
            >
              Reservar Ahora
            </Link>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

import React, { useState } from 'react';
import { Compass, Camera, Utensils, Info, Sparkles } from 'lucide-react';
import { GoogleGenAI } from '@google/genai';

const Guide: React.FC = () => {
  const categories = [
    { 
      id: 'nature', 
      title: 'Naturaleza', 
      icon: <Compass />, 
      items: [
        { title: 'El Torcal de Antequera', desc: 'Paisaje kárstico único en el mundo con rutas de senderismo impresionantes.' },
        { title: 'Caminito del Rey', desc: 'A tan solo 50 minutos, una de las rutas más famosas de España.' }
      ]
    },
    { 
      id: 'culture', 
      title: 'Cultura', 
      icon: <Camera />, 
      items: [
        { title: 'Dólmenes de Antequera', desc: 'Patrimonio de la Humanidad por la UNESCO. Un viaje al pasado.' },
        { title: 'Casco Histórico', desc: 'La Colegiata de Santa María y la Alcazaba ofrecen vistas espectaculares.' }
      ]
    },
    { 
      id: 'gastronomy', 
      title: 'Gastronomía', 
      icon: <Utensils />, 
      items: [
        { title: 'Porra Antequerana', desc: 'Plato estrella local que no te puedes perder.' },
        { title: 'Molletes de Antequera', desc: 'El desayuno perfecto para empezar el día con energía.' }
      ]
    }
  ];

  // AI Assistant Feature
  const [query, setQuery] = useState('');
  const [aiResponse, setAiResponse] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const askAssistant = async () => {
    if (!query) return;
    setLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Eres un experto guía local de Antequera y los Montes de Málaga para Casa Rural Furones. Responde de forma cálida y profesional en español. Pregunta del huésped: ${query}`,
      });
      setAiResponse(response.text || "Lo siento, no he podido generar una respuesta.");
    } catch (error) {
      setAiResponse("Estamos actualizando nuestro asistente local. Por favor, inténtalo de nuevo más tarde.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="pt-24">
      {/* Header */}
      <section className="bg-[#F3F4F1] py-20">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <span className="text-[#8C7B65] font-bold uppercase tracking-widest text-sm mb-4 block">Consejos Locales</span>
          <h1 className="text-5xl md:text-6xl font-bold mb-6 serif">Guía Insider Antequera</h1>
          <p className="text-gray-600 max-w-2xl mx-auto text-lg">
            Te descubrimos los secretos mejor guardados de nuestra región. Desde rutas senderistas hasta los mejores restaurantes locales.
          </p>
        </div>
      </section>

      {/* Guide Grid */}
      <section className="py-24 max-w-7xl mx-auto px-4">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-12">
          {categories.map((cat) => (
            <div key={cat.id} className="space-y-8">
              <div className="flex items-center gap-4 border-b border-gray-200 pb-4">
                <div className="p-3 bg-[#4A5D4E] text-white rounded-xl">
                  {React.cloneElement(cat.icon as React.ReactElement, { size: 24 })}
                </div>
                <h2 className="text-2xl font-bold serif">{cat.title}</h2>
              </div>
              <div className="space-y-6">
                {cat.items.map((item, idx) => (
                  <div key={idx} className="group cursor-default">
                    <div className="aspect-video bg-gray-200 rounded-xl mb-4 overflow-hidden">
                       <img src={`https://picsum.photos/600/400?sig=${cat.id}${idx}`} alt={item.title} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" />
                    </div>
                    <h3 className="text-xl font-bold mb-2">{item.title}</h3>
                    <p className="text-gray-500 leading-relaxed">{item.desc}</p>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* AI Assistant Section */}
      <section className="py-24 bg-[#1A1A1A] text-white">
        <div className="max-w-4xl mx-auto px-4 text-center">
          <div className="inline-flex items-center gap-2 bg-[#8C7B65] px-4 py-1 rounded-full text-xs font-bold uppercase tracking-widest mb-6">
            <Sparkles size={14} /> Asistente Furones AI
          </div>
          <h2 className="text-4xl font-bold mb-8 serif">¿Planeando tu estancia? Pregúntanos.</h2>
          <div className="relative max-w-2xl mx-auto mb-12">
            <input 
              type="text" 
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="Ej: ¿Qué ruta de senderismo recomiendas para niños?"
              className="w-full bg-white/5 border border-white/20 rounded-2xl py-6 px-8 text-white focus:outline-none focus:ring-2 focus:ring-[#8C7B65] transition-all"
            />
            <button 
              onClick={askAssistant}
              disabled={loading}
              className="absolute right-3 top-3 bottom-3 bg-[#8C7B65] px-8 rounded-xl font-bold hover:bg-[#7a6a56] transition-colors disabled:opacity-50"
            >
              {loading ? 'Consultando...' : 'Preguntar'}
            </button>
          </div>

          {aiResponse && (
            <div className="bg-white/5 rounded-3xl p-8 text-left border border-white/10 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="flex gap-4">
                <div className="shrink-0 w-10 h-10 bg-[#4A5D4E] rounded-full flex items-center justify-center">
                  <Sparkles size={20} />
                </div>
                <div>
                  <p className="text-lg leading-relaxed text-gray-300 italic">
                    "{aiResponse}"
                  </p>
                </div>
              </div>
            </div>
          )}
        </div>
      </section>

      {/* Practical Info */}
      <section className="py-24 bg-white">
        <div className="max-w-7xl mx-auto px-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-16">
            <div className="bg-[#FAF9F6] p-12 rounded-[2rem]">
              <h3 className="text-3xl font-bold mb-8 serif">Información Práctica</h3>
              <ul className="space-y-6">
                <li className="flex gap-4">
                  <Info className="text-[#8C7B65] shrink-0" />
                  <div>
                    <span className="font-bold block mb-1">Check-in / Check-out</span>
                    <span className="text-gray-500">Entrada a partir de las 16:00. Salida antes de las 11:00.</span>
                  </div>
                </li>
                <li className="flex gap-4">
                  <Info className="text-[#8C7B65] shrink-0" />
                  <div>
                    <span className="font-bold block mb-1">Supermercados</span>
                    <span className="text-gray-500">A 15 min en Antequera encontrarás Mercadona, Carrefour y Lidl.</span>
                  </div>
                </li>
                <li className="flex gap-4">
                  <Info className="text-[#8C7B65] shrink-0" />
                  <div>
                    <span className="font-bold block mb-1">Acceso</span>
                    <span className="text-gray-500">Último kilómetro por carril de tierra en buen estado. Apto para cualquier turismo.</span>
                  </div>
                </li>
              </ul>
            </div>
            <div className="rounded-[2rem] overflow-hidden shadow-2xl">
               <img src="https://picsum.photos/800/800?4" alt="Mapa" className="w-full h-full object-cover" />
            </div>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Guide;

