import Guide from './pages/Guide';
import Booking from './pages/Booking';
import Privacy from './pages/Privacy';
import { TranslationProvider } from './TranslationContext';

const App: React.FC = () => {
  return (
    <TranslationProvider>
      <Router>
        <div className="flex flex-col min-h-screen">
          <Navbar />
          <main className="flex-grow">
            <Routes>
              <Route path="/" element={<Home />} />
              <Route path="/guia-insider" element={<Guide />} />
              <Route path="/reservar" element={<Booking />} />
              <Route path="/privacidad" element={<Privacy />} />
            </Routes>
          </main>
          <Footer />
        </div>
      </Router>
    </TranslationProvider>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Menu, X, ChevronRight, Globe } from 'lucide-react';
import { useTranslation } from '../TranslationContext';

const Navbar: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const { lang, setLang, t } = useTranslation();
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { name: t('nav_home'), path: '/' },
    { name: t('nav_guide'), path: '/guia-insider' },
  ];

  const isActive = (path: string) => location.pathname === path;

  return (
    <nav className={`fixed w-full z-50 transition-all duration-300 ${isScrolled ? 'bg-white/95 backdrop-blur-md shadow-sm py-3' : 'bg-transparent py-6'}`}>
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center">
          <Link to="/" className="flex flex-col items-center">
            <span className={`text-2xl font-bold tracking-tighter serif ${isScrolled ? 'text-[#4A5D4E]' : 'text-white'}`}>
              Furones
            </span>
            <span className={`text-[10px] uppercase tracking-widest ${isScrolled ? 'text-[#8C7B65]' : 'text-white/80'}`}>
              Casa Rural · Málaga
            </span>
          </Link>

          {/* Desktop Nav */}
          <div className="hidden md:flex items-center space-x-8">
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                className={`text-sm font-medium transition-colors hover:text-[#8C7B65] ${
                  isActive(link.path) 
                    ? (isScrolled ? 'text-[#8C7B65]' : 'text-white border-b border-white/30') 
                    : (isScrolled ? 'text-[#4A5D4E]' : 'text-white/90')
                }`}
              >
                {link.name}
              </Link>
            ))}

            {/* Language Switcher */}
            <button 
              onClick={() => setLang(lang === 'es' ? 'en' : 'es')}
              className={`flex items-center gap-2 text-xs font-bold uppercase tracking-widest px-3 py-1 rounded-full border transition-all ${
                isScrolled 
                ? 'border-[#4A5D4E] text-[#4A5D4E] hover:bg-[#4A5D4E] hover:text-white' 
                : 'border-white/30 text-white hover:bg-white/10'
              }`}
            >
              <Globe size={14} />
              {lang === 'es' ? 'EN' : 'ES'}
            </button>

            <Link
              to="/reservar"
              className={`px-6 py-2 rounded-full text-sm font-semibold transition-all flex items-center gap-2 ${
                isScrolled 
                  ? 'bg-[#4A5D4E] text-white hover:bg-[#3D4D40]' 
                  : 'bg-white text-[#4A5D4E] hover:bg-white/90 shadow-xl'
              }`}
            >
              {t('nav_book')} <ChevronRight size={16} />
            </Link>
          </div>

          {/* Mobile Menu Button */}
          <div className="md:hidden flex items-center gap-4">
            <button 
              onClick={() => setLang(lang === 'es' ? 'en' : 'es')}
              className={`${isScrolled ? 'text-[#4A5D4E]' : 'text-white'} text-sm font-bold`}
            >
              {lang === 'es' ? 'EN' : 'ES'}
            </button>
            <button
              onClick={() => setIsOpen(!isOpen)}
              className={`${isScrolled ? 'text-[#4A5D4E]' : 'text-white'}`}
            >
              {isOpen ? <X size={28} /> : <Menu size={28} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Nav */}
      {isOpen && (
        <div className="md:hidden absolute top-full left-0 w-full bg-white shadow-2xl animate-in slide-in-from-top duration-300">
          <div className="px-4 pt-2 pb-6 space-y-1">
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                onClick={() => setIsOpen(false)}
                className="block px-3 py-4 text-lg font-medium text-[#4A5D4E] border-b border-gray-100"
              >
                {link.name}
              </Link>
            ))}
            <Link
              to="/reservar"
              onClick={() => setIsOpen(false)}
              className="block w-full text-center mt-4 px-3 py-4 bg-[#4A5D4E] text-white rounded-lg font-bold"
            >
              {t('nav_book')}
            </Link>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

